INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_AC-1a', 'AC-1a — AC-1 Access Control Policy and Procedures', 'a. Develop, document, and disseminate to all associates and any individuals contracted to perform services for Kroger, and all systems used by associates and  individuals contracted to perform services for Kroger.  1. Organization level: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the access control policy and the associated access controls', 'KROGER_CCF', TRUE, 'Access Control');
