INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_AC-8a', 'AC-8a — AC-8 System Use Notification', 'a. Display the below disclaimer to users before granting access to the system that provides privacy and security notices consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines and state that: "You have accessed networks or systems owned or controlled by The Kroger Co. and its family of companies (collectively, “the Company”). Unauthorized access is prohibited and is subject to prosecution to the full extent of the law. Except where applicable law provides otherwise, you should have no expectation of privacy when using networks or systems owned or controlled by the Company, including, but not limited to, transmitting and storing files, data, and messages. To enforce compliance with the Company’s policies and protect the Company’s interests, the Company reserves the right to monitor any use of its networks and systems to the extent permitted by applicable law. By using networks or systems owned or controlled by the Company, you agree to such monitoring. Monitoring may include (but is not necessarily limited to) intercepting and reviewing network traffic, emails, or other messages sent or received and inspecting data stored on individual file directories, hard disks, or other printed or electronic media."', 'KROGER_CCF', TRUE, 'Access Control');
INSERT INTO questions (control_id, question_text, display_order, help_text, ask_owner) VALUES ((SELECT id FROM controls WHERE control_id = 'KCF_AC-8a'), 'Attest to this control requirement: a. Display the below disclaimer to users before granting access to the system that provides privacy and security notices consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines and state that: "You have accessed networks or systems owned or controlled by The Kroger Co. and its family of companies (collectively, “the Company”). Unauthorized access is prohibited and is subject to prosecution to the full extent of the law. Except where applicable law provides otherwise, you should have no expectation of privacy when using networks or systems owned or controlled by the Company, including, but not limited to, transmitting and storing files, data, and messages. To enforce compliance with the Company’s policies and protect the Company’s interests, the Company reserves the right to monitor any use of its networks and systems to the extent permitted by applicable law. By using networks or systems owned or controlled by the Company, you agree to such monitoring. Monitoring may include (but is not necessarily limited to) intercepting and reviewing network traffic, emails, or other messages sent or received and inspecting data stored on individual file directories, hard disks, or other printed or electronic media."', 0, 'CCF ID: AC-8a. Related control: AC-8 System Use Notification', TRUE);
INSERT INTO question_control_mappings (question_id, control_id) SELECT q.id, c.id FROM questions q JOIN controls c ON c.control_id = 'KCF_AC-8a' AND q.control_id = c.id WHERE NOT EXISTS (SELECT 1 FROM question_control_mappings m WHERE m.question_id = q.id AND m.control_id = c.id);
