INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_AU-2c', 'AU-2c —', 'c. Specify the following event types for logging within the system:  The following user events must be logged:  	• User log in and log out, including any unsuccessful or rejected log in attempts.  	• All attempts to access databases storing Kroger internal, confidential, or highly confidential data and definitions.  	• All attempts to access definitions, passwords, and other secrets belonging to the access control system.  	• Actions performed, including create, read, update, modify, delete, and move any files, system-level objects, and data, including Kroger internal, confidential, or highly confidential information.  	• All privileged and administrator activity within the network.  	• Access provisions, modifications, and deletions, including granting, modifying, and revoking access rights; adding a new user or group; changing user privilege levels; changing file or database object permissions; changing firewall rules; and user password changes.  	• Activation and deactivation of all network components, systems, applications, and services to include antivirus and intrusion detection systems (IDS).  	• System, network, or services configuration changes, including installation of software patches and updates and other installed software changes  The following system and network events must be logged:  	• Create, read, update, or delete regulated or highly confidential information, including authentication information such as passwords.  	• All alarms within the network.  	• All remote and network connections (initiate or accept).  	• Application process startup, shutdown, or restart.  	• Application process abort, failure, or abnormal end, especially due to resource exhaustion or reaching a resource limit/threshold (such as for CPU, memory, network connections, network bandwidth, or disk space) or the failure of network services (such as for DHCP, DNS, or hardware fault).  	• Detection of suspicious or malicious activity such as intrusion detection or prevention systems (IDS /IPS), antivirus systems, or anti-spyware systems. ', 'KROGER_CCF', TRUE, 'Audit & Accountability');
INSERT INTO questions (control_id, question_text, display_order, help_text, ask_owner) VALUES ((SELECT id FROM controls WHERE control_id = 'KCF_AU-2c'), 'Attest to this control requirement: c. Specify the following event types for logging within the system:  The following user events must be logged:  	• User log in and log out, including any unsuccessful or rejected log in attempts.  	• All attempts to access databases storing Kroger internal, confidential, or highly confidential data and definitions.  	• All attempts to access definitions, passwords, and other secrets belonging to the access control system.  	• Actions performed, including create, read, update, modify, delete, and move any files, system-level objects, and data, including Kroger internal, confidential, or highly confidential information.  	• All privileged and administrator activity within the network.  	• Access provisions, modifications, and deletions, including granting, modifying, and revoking access rights; adding a new user or group; changing user privilege levels; changing file or database object permissions; changing firewall rules; and user password changes.  	• Activation and deactivation of all network components, systems, applications, and services to include antivirus and intrusion detection systems (IDS).  	• System, network, or services configuration changes, including installation of software patches and updates and other installed software changes  The following system and network events must be logged:  	• Create, read, update, or delete regulated or highly confidential information, including authentication information such as passwords.  	• All alarms within the network.  	• All remote and network connections (initiate or accept).  	• Application process startup, shutdown, or restart.  	• Application process abort, failure, or abnormal end, especially due to resource exhaustion or reaching a resource limit/threshold (such as for CPU, memory, network connections, network bandwidth, or disk space) or the failure of network services (such as for DHCP, DNS, or hardware fault).  	• Detection of suspicious or malicious activity', 0, 'CCF ID: AU-2c. Related control:  ', TRUE);
