INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_CA-1a', 'CA-1a — CA-1 Assessment, Authorization & Monitoring Policy and Procedures', 'a. Develop, document, and disseminate to all Kroger associates:  1. Organization-level assessment, authorization, and monitoring policy that:  (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the assessment, authorization, and monitoring policy and the associated assessment, authorization, and monitoring controls;', 'KROGER_CCF', TRUE, 'Assessment, Authorization & Monitoring');
