INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_IA-5-1', 'IA-5-1 — IA-5(1) Authenticator Management | Password-based Authentication', 'For password-based authentication:  (a) Maintain a list of commonly-used, expected, or compromised passwords and update the list as needed and when organizational passwords are suspected to have been compromised directly or indirectly; (b) Verify, when users create or update passwords, that the passwords are not found on the list of commonly-used, expected, or compromised passwords in IA-5(1)(a); (c) Transmit passwords only over cryptographically-protected channels; (d) Store passwords using an approved salted key derivation function, preferably using a keyed hash; (e) Require immediate selection of a new password upon account recovery; (f) Allow user selection of long passwords and passphrases, including spaces and all printable characters; (g) Employ automated tools to assist the user in selecting strong password authenticators; and (h) Enforce the following composition and complexity rules: 	• Password minimum length is eight characters. 	• Passwords must contain at least one number.  	• Passwords must contain at least one capital letter. 	• If special characters are supported, the password must contain at least one special character.  	• For AS400 accounts, the password must begin with a letter.  	• Passwords must not contain any common words, phrases, personally identifiable information, or patterns that make the password easy to guess. This includes repeated patterns (e.g., 11111 or AAAAA) or sequential patterns (e.g., 12345, abcdef, or jkl;). ', 'KROGER_CCF', TRUE, 'Identification & Authentication');
INSERT INTO questions (control_id, question_text, display_order, help_text, ask_owner) VALUES ((SELECT id FROM controls WHERE control_id = 'KCF_IA-5-1'), 'Attest to this control requirement: For password-based authentication:  (a) Maintain a list of commonly-used, expected, or compromised passwords and update the list as needed and when organizational passwords are suspected to have been compromised directly or indirectly; (b) Verify, when users create or update passwords, that the passwords are not found on the list of commonly-used, expected, or compromised passwords in IA-5(1)(a); (c) Transmit passwords only over cryptographically-protected channels; (d) Store passwords using an approved salted key derivation function, preferably using a keyed hash; (e) Require immediate selection of a new password upon account recovery; (f) Allow user selection of long passwords and passphrases, including spaces and all printable characters; (g) Employ automated tools to assist the user in selecting strong password authenticators; and (h) Enforce the following composition and complexity rules: 	• Password minimum length is eight characters. 	• Passwords must contain at least one number.  	• Passwords must contain at least one capital letter. 	• If special characters are supported, the password must contain at least one special character.  	• For AS400 accounts, the password must begin with a letter.  	• Passwords must not contain any common words, phrases, personally identifiable information, or patterns that make the password easy to guess. This includes repeated patterns (e.g., 11111 or AAAAA) or sequential patterns (e.g., 12345, abcdef, or jkl;). ', 0, 'CCF ID: IA-5-1. Related control: IA-5(1) Authenticator Management | Password-based Authentication', TRUE);
INSERT INTO question_control_mappings (question_id, control_id) SELECT q.id, c.id FROM questions q JOIN controls c ON c.control_id = 'KCF_IA-5-1' AND q.control_id = c.id WHERE NOT EXISTS (SELECT 1 FROM question_control_mappings m WHERE m.question_id = q.id AND m.control_id = c.id);
