INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_IR-1a', 'IR-1a — IR-1 Incident Response Policy and Procedures', 'a. Develop, document, and disseminate to all employees, contractors, vendors, and any other individuals who have access to the organization''s information systems and data:  1.  Organization-level and System-level incident response policy that:  (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the incident response policy and the associated incident response controls;', 'KROGER_CCF', TRUE, 'Incident Response');
INSERT INTO questions (control_id, question_text, display_order, help_text, ask_owner) VALUES ((SELECT id FROM controls WHERE control_id = 'KCF_IR-1a'), 'Attest to this control requirement: a. Develop, document, and disseminate to all employees, contractors, vendors, and any other individuals who have access to the organization''s information systems and data:  1.  Organization-level and System-level incident response policy that:  (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the incident response policy and the associated incident response controls;', 0, 'CCF ID: IR-1a. Related control: IR-1 Incident Response Policy and Procedures', TRUE);
