INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_IR-8a', 'IR-8a — IR-8 Incident Response Plan', 'a. Develop an incident response plan that:  1. Provides the organization with a roadmap for implementing its incident response capability; 2. Describes the structure and organization of the incident response capability; 3. Provides a high-level approach for how the incident response capability fits into the overall organization; 4. Meets the unique requirements of the organization, which relate to mission, size, structure, and functions; 5. Defines reportable incidents; 6. Provides metrics for measuring the incident response capability within the organization; 7. Defines the resources and management support needed to effectively maintain and mature an incident response capability; 8. Addresses the sharing of incident information; 9. Is reviewed and approved by Kroger Support Center and iSOC; and 10. Explicitly designates responsibility for incident response to Kroger Support Center and iSOC.', 'KROGER_CCF', TRUE, 'Incident Response');
INSERT INTO questions (control_id, question_text, display_order, help_text, ask_owner) VALUES ((SELECT id FROM controls WHERE control_id = 'KCF_IR-8a'), 'Attest to this control requirement: a. Develop an incident response plan that:  1. Provides the organization with a roadmap for implementing its incident response capability; 2. Describes the structure and organization of the incident response capability; 3. Provides a high-level approach for how the incident response capability fits into the overall organization; 4. Meets the unique requirements of the organization, which relate to mission, size, structure, and functions; 5. Defines reportable incidents; 6. Provides metrics for measuring the incident response capability within the organization; 7. Defines the resources and management support needed to effectively maintain and mature an incident response capability; 8. Addresses the sharing of incident information; 9. Is reviewed and approved by Kroger Support Center and iSOC; and 10. Explicitly designates responsibility for incident response to Kroger Support Center and iSOC.', 0, 'CCF ID: IR-8a. Related control: IR-8 Incident Response Plan', TRUE);
