INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_PL-1a', 'PL-1a — PL-1 Planning Policy and Procedures', 'a. Develop, document, and disseminate to all employees, contractors, and third-party vendors who have access to Kroger''s information technology systems, data, or networks:  1. Organization-level and System-level planning policy that:  (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the planning policy and the associated planning controls;', 'KROGER_CCF', TRUE, 'Planning');
