INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_PL-2a', 'PL-2a — PL-2 System Security and Privacy Plans', 'a. Develop security and privacy plans for the system that:  1. Are consistent with the organization & enterprise architecture; 2. Explicitly define the constituent system components; 3. Describe the operational context of the system in terms of mission and business processes; 4. Identify the individuals that fulfill system roles and responsibilities; 5. Identify the information types processed, stored, and transmitted by the system; 6. Provide the security categorization of the system, including supporting rationale; 7. Describe any specific threats to the system that are of concern to the organization; 8. Provide the results of a privacy risk assessment for systems processing personally identifiable information; 9. Describe the operational environment for the system and any dependencies on or connections to other systems or system components; 10. Provide an overview of the security and privacy requirements for the system; 11. Identify any relevant control baselines or overlays, if applicable; 12. Describe the controls in place or planned for meeting the security and privacy requirements, including a rationale for any tailoring decisions; 13. Include risk determinations for security and privacy architecture and design decisions; 14. Include security- and privacy-related activities affecting the system that require planning and coordination with CIS, Privacy, Legal, Third Party Risk, Responsible AI committee, system owner; and 15. Are reviewed and approved by the authorizing official or designated representative prior to plan implementation.', 'KROGER_CCF', TRUE, 'Planning');
INSERT INTO questions (control_id, question_text, display_order, help_text, ask_owner) VALUES ((SELECT id FROM controls WHERE control_id = 'KCF_PL-2a'), 'Attest to this control requirement: a. Develop security and privacy plans for the system that:  1. Are consistent with the organization & enterprise architecture; 2. Explicitly define the constituent system components; 3. Describe the operational context of the system in terms of mission and business processes; 4. Identify the individuals that fulfill system roles and responsibilities; 5. Identify the information types processed, stored, and transmitted by the system; 6. Provide the security categorization of the system, including supporting rationale; 7. Describe any specific threats to the system that are of concern to the organization; 8. Provide the results of a privacy risk assessment for systems processing personally identifiable information; 9. Describe the operational environment for the system and any dependencies on or connections to other systems or system components; 10. Provide an overview of the security and privacy requirements for the system; 11. Identify any relevant control baselines or overlays, if applicable; 12. Describe the controls in place or planned for meeting the security and privacy requirements, including a rationale for any tailoring decisions; 13. Include risk determinations for security and privacy architecture and design decisions; 14. Include security- and privacy-related activities affecting the system that require planning and coordination with CIS, Privacy, Legal, Third Party Risk, Responsible AI committee, system owner; and 15. Are reviewed and approved by the authorizing official or designated representative prior to plan implementation.', 0, 'CCF ID: PL-2a. Related control: PL-2 System Security and Privacy Plans', TRUE);
INSERT INTO question_control_mappings (question_id, control_id) SELECT q.id, c.id FROM questions q JOIN controls c ON c.control_id = 'KCF_PL-2a' AND q.control_id = c.id WHERE NOT EXISTS (SELECT 1 FROM question_control_mappings m WHERE m.question_id = q.id AND m.control_id = c.id);
