INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_RA-1a', 'RA-1a — RA-1 Risk Assessment Policy and Procedures', 'a. Develop, document, and disseminate to all employees, contractors, and third-party vendors who have access to Kroger''s information technology systems, data, or networks:  1. Organization-level and System-level risk assessment policy that:  (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the risk assessment policy and the associated risk assessment controls;', 'KROGER_CCF', TRUE, 'Risk Assessment');
