INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_SC-12', 'SC-12 — SC-12 Cryptographic Key Establishment and Management', 'Establish and manage cryptographic keys when cryptography is employed within the system in accordance with the following key management requirements: CIS maintains a secure environment to protect the cryptographic keys used to encrypt and decrypt  information. Keys must be securely distributed and stored. The following standards apply:  	• Access to keys must be restricted to identities that have a business need for access.  	• Encryption keys must not be stored with the data they encrypt.  	• The compromise of a cryptographic key will cause all data encrypted with that key to be considered unencrypted. If a compromised key is discovered, a new key must be generated and used to re-encrypt the data. Report compromised keys and security incidents to isoc@kroger.com.  	• The key management systems approved by CIS must be used. This does not include personal key pairs used solely by an individual Kroger associate.', 'KROGER_CCF', TRUE, 'System & Communications Protection');
INSERT INTO questions (control_id, question_text, display_order, help_text, ask_owner) VALUES ((SELECT id FROM controls WHERE control_id = 'KCF_SC-12'), 'Attest to this control requirement: Establish and manage cryptographic keys when cryptography is employed within the system in accordance with the following key management requirements: CIS maintains a secure environment to protect the cryptographic keys used to encrypt and decrypt  information. Keys must be securely distributed and stored. The following standards apply:  	• Access to keys must be restricted to identities that have a business need for access.  	• Encryption keys must not be stored with the data they encrypt.  	• The compromise of a cryptographic key will cause all data encrypted with that key to be considered unencrypted. If a compromised key is discovered, a new key must be generated and used to re-encrypt the data. Report compromised keys and security incidents to isoc@kroger.com.  	• The key management systems approved by CIS must be used. This does not include personal key pairs used solely by an individual Kroger associate.', 0, 'CCF ID: SC-12. Related control: SC-12 Cryptographic Key Establishment and Management', TRUE);
INSERT INTO question_control_mappings (question_id, control_id) SELECT q.id, c.id FROM questions q JOIN controls c ON c.control_id = 'KCF_SC-12' AND q.control_id = c.id WHERE NOT EXISTS (SELECT 1 FROM question_control_mappings m WHERE m.question_id = q.id AND m.control_id = c.id);
