INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_SR-1a', 'SR-1a — SR-1 Supply Chain Risk Management Policy and Procedures', 'a. Develop, document, and disseminate to all Kroger associates and third-party vendors: 1. Organization-level supply chain risk management policy (Third Party Cyber Security Policy) that: (a) Addresses purpose, scope, roles, responsibilities, management commitment, coordination among organizational entities, and compliance; and (b) Is consistent with applicable laws, executive orders, directives, regulations, policies, standards, and guidelines; and 2. Procedures to facilitate the implementation of the supply chain risk management policy and the associated supply chain risk management controls', 'KROGER_CCF', TRUE, 'Supply Chain Risk Management');
