INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_SR-3a', 'SR-3a — SR-3 Supply Chain Controls and Processes', 'a. Establish a process or processes to identify and address weaknesses or deficiencies in the supply chain elements and processes of any third-party technology-related hardware or software installed at a Kroger location in coordination with Corporate Information Security (CIS), Kroger Privacy Legal group, Data Sharing Governance Council, and Third Party Risk Management', 'KROGER_CCF', TRUE, 'Supply Chain Risk Management');
INSERT INTO questions (control_id, question_text, display_order, help_text, ask_owner) VALUES ((SELECT id FROM controls WHERE control_id = 'KCF_SR-3a'), 'Attest to this control requirement: a. Establish a process or processes to identify and address weaknesses or deficiencies in the supply chain elements and processes of any third-party technology-related hardware or software installed at a Kroger location in coordination with Corporate Information Security (CIS), Kroger Privacy Legal group, Data Sharing Governance Council, and Third Party Risk Management', 0, 'CCF ID: SR-3a. Related control: SR-3 Supply Chain Controls and Processes', TRUE);
INSERT INTO question_control_mappings (question_id, control_id) SELECT q.id, c.id FROM questions q JOIN controls c ON c.control_id = 'KCF_SR-3a' AND q.control_id = c.id WHERE NOT EXISTS (SELECT 1 FROM question_control_mappings m WHERE m.question_id = q.id AND m.control_id = c.id);
INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_SR-3b', 'SR-3b —', 'b. Employ the following controls to protect against supply chain risks to the system, system component, or system service and to limit the harm or consequences from supply chain-related events:  • All third parties and vendors identified as Tier 1 or Tier 2 must complete a cybersecurity assessment provided by and reviewed by Corporate Information Security (CIS). • A completed third-party cybersecurity assessment must be conducted on a cadence determined by CIS that is no more than every three years. • Active vendors who have completed a cybersecurity assessment must be monitored for cyber security–related incidents on an ongoing basis. • Any vendor that stores or processes Kroger PI data must be able to comply with the applicable state privacy regulations, complete a Privacy Impact Assessment (PIA), and have their contract with Kroger reviewed by the Kroger Privacy Legal group. • Any project that shares data with a third party must be reviewed and approved by the Data Sharing Governance Council prior to sharing data with the third party. “Data sharing” includes hosted applications where identity data is exchanged via single sign-on (SSO). • Any externally hosted application must be hosted entirely within the United States. This includes the application, the data, and any failover sites. • Any hosted application must utilize Kroger-approved authentication services, such as federated single sign-on, for access to the application. • Third parties that wish to send email on behalf of Kroger using a *.kroger.com domain must comply with Email Domain Usage Standard. • At least annually, at its own expense, each vendor shall engage a third-party service provider for penetration testing of vendor systems (including web applications, APIs, and mobile apps) that host or process Kroger data and, upon request, provide Kroger with an executive overview of such testing. • The method of test scoring and issue ratings shall follow standard industry practice, such as the latest Common Vulnerability Scoring System (CVSS) published by NIST. • For any material findings (critical, priority, or high risk), the vendor shall prepare and provide to Kroger a remediation plan detailing when the security issues identified in the penetration testing will be fully resolved within 60 days of test completion. 4.10   A Vendor Extranet Agreement or other Kroger Legal–approved agreement is required for any third party or vendor with remote access to Kroger internal systems. Remote access to Supplier Hub is excluded from this. 4.11   If a vendor stores Kroger data on a portable device, on devices not owned or managed by the vendor, or on any approved cloud-hosted infrastructure, it should be encrypted at rest using AES 256-bit encryption or better. This does not apply to data classified as “public.” 4.12   All communications between external sources are required to use encrypted communication channels using secure communication protocols.   4.12.1   Clear-text communication protocols including FTP, HTTP and TELNET are strictly prohibited.   4.12.2   Where technical or business constraints require use of older services, daemons, or protocols, additional security features must be documented and implemented.', 'KROGER_CCF', TRUE, 'Supply Chain Risk Management');
INSERT INTO questions (control_id, question_text, display_order, help_text, ask_owner) VALUES ((SELECT id FROM controls WHERE control_id = 'KCF_SR-3b'), 'Attest to this control requirement: b. Employ the following controls to protect against supply chain risks to the system, system component, or system service and to limit the harm or consequences from supply chain-related events:  • All third parties and vendors identified as Tier 1 or Tier 2 must complete a cybersecurity assessment provided by and reviewed by Corporate Information Security (CIS). • A completed third-party cybersecurity assessment must be conducted on a cadence determined by CIS that is no more than every three years. • Active vendors who have completed a cybersecurity assessment must be monitored for cyber security–related incidents on an ongoing basis. • Any vendor that stores or processes Kroger PI data must be able to comply with the applicable state privacy regulations, complete a Privacy Impact Assessment (PIA), and have their contract with Kroger reviewed by the Kroger Privacy Legal group. • Any project that shares data with a third party must be reviewed and approved by the Data Sharing Governance Council prior to sharing data with the third party. “Data sharing” includes hosted applications where identity data is exchanged via single sign-on (SSO). • Any externally hosted application must be hosted entirely within the United States. This includes the application, the data, and any failover sites. • Any hosted application must utilize Kroger-approved authentication services, such as federated single sign-on, for access to the application. • Third parties that wish to send email on behalf of Kroger using a *.kroger.com domain must comply with Email Domain Usage Standard. • At least annually, at its own expense, each vendor shall engage a third-party service provider for penetration testing of vendor systems (including web applications, APIs, and mobile apps) that host or process Kroger data and, upon request, provide Kroger with an executive overview of such testing. • The method of test scoring and issue ratings shall follow standa', 0, 'CCF ID: SR-3b. Related control:  ', TRUE);
