INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_SR-5', 'SR-5 — SR-5 Acquisition Strategies, Tools, and Methods', 'Employ the following acquisition strategies, contract tools, and procurement methods to protect against, identify, and mitigate supply chain risks:  • All third parties and vendors identified as Tier 1 or Tier 2 must have an NDA on file with Kroger. • An NDA can be accomplished via an NDA document, the BAA or DAA document, through specific language within the MSA, or via the ECA/NDA combined agreement. • The Kroger Legal department has the final approval of acceptable NDA language and owns the Kroger NDA template. • All third parties and vendors identified as Tier 1 or Tier 2 must complete a cybersecurity assessment provided by and reviewed by Corporate Information Security (CIS). • A completed third-party cybersecurity assessment must be conducted on a cadence determined by CIS that is no more than every three years. • Active vendors who have completed a cybersecurity assessment must be monitored for cyber security–related incidents on an ongoing basis.', 'KROGER_CCF', TRUE, 'Supply Chain Risk Management');
INSERT INTO questions (control_id, question_text, display_order, help_text, ask_owner) VALUES ((SELECT id FROM controls WHERE control_id = 'KCF_SR-5'), 'Attest to this control requirement: Employ the following acquisition strategies, contract tools, and procurement methods to protect against, identify, and mitigate supply chain risks:  • All third parties and vendors identified as Tier 1 or Tier 2 must have an NDA on file with Kroger. • An NDA can be accomplished via an NDA document, the BAA or DAA document, through specific language within the MSA, or via the ECA/NDA combined agreement. • The Kroger Legal department has the final approval of acceptable NDA language and owns the Kroger NDA template. • All third parties and vendors identified as Tier 1 or Tier 2 must complete a cybersecurity assessment provided by and reviewed by Corporate Information Security (CIS). • A completed third-party cybersecurity assessment must be conducted on a cadence determined by CIS that is no more than every three years. • Active vendors who have completed a cybersecurity assessment must be monitored for cyber security–related incidents on an ongoing basis.', 0, 'CCF ID: SR-5. Related control: SR-5 Acquisition Strategies, Tools, and Methods', TRUE);
INSERT INTO question_control_mappings (question_id, control_id) SELECT q.id, c.id FROM questions q JOIN controls c ON c.control_id = 'KCF_SR-5' AND q.control_id = c.id WHERE NOT EXISTS (SELECT 1 FROM question_control_mappings m WHERE m.question_id = q.id AND m.control_id = c.id);
