INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_SR-11-2', 'SR-11-2 — SR-11(2) Component Authenticity | Configuration Control for Component Service and Repair', 'Maintain configuration control over the following system components awaiting service or repair and serviced or repaired components awaiting return to service: all non-leased Kroger technology hardware, including but not limited to the following technology platforms: point of sale, payment terminals, PCs, monitors, printers, handheld devices, servers, network, fuel, CCTV, telephony, and lift truck–mounted computers', 'KROGER_CCF', TRUE, 'Supply Chain Risk Management');
