INSERT INTO controls (control_id, name, description, framework, enabled, category) VALUES ('KCF_SR-12', 'SR-12 — SR-12 Component Disposal', 'Dispose of all non-leased Kroger technology hardware, including but not limited to the following technology platforms: point of sale, payment terminals, PCs, monitors, printers, handheld devices, servers, network, fuel, CCTV, telephony, and lift truck–mounted computers, and storage media; all company and customer data using the following techniques and methods: Shredding (standard) for hard drives and payment terminals Hard drive DOD data sanitization (wipe upon request)  Removal of all company identification tags Clearing all passwords and devices reset to factory or default configurations. Non-functioning storage or memory devices removed and physically destroyed.', 'KROGER_CCF', TRUE, 'Supply Chain Risk Management');
INSERT INTO questions (control_id, question_text, display_order, help_text, ask_owner) VALUES ((SELECT id FROM controls WHERE control_id = 'KCF_SR-12'), 'Attest to this control requirement: Dispose of all non-leased Kroger technology hardware, including but not limited to the following technology platforms: point of sale, payment terminals, PCs, monitors, printers, handheld devices, servers, network, fuel, CCTV, telephony, and lift truck–mounted computers, and storage media; all company and customer data using the following techniques and methods: Shredding (standard) for hard drives and payment terminals Hard drive DOD data sanitization (wipe upon request)  Removal of all company identification tags Clearing all passwords and devices reset to factory or default configurations. Non-functioning storage or memory devices removed and physically destroyed.', 0, 'CCF ID: SR-12. Related control: SR-12 Component Disposal', TRUE);
INSERT INTO question_control_mappings (question_id, control_id) SELECT q.id, c.id FROM questions q JOIN controls c ON c.control_id = 'KCF_SR-12' AND q.control_id = c.id WHERE NOT EXISTS (SELECT 1 FROM question_control_mappings m WHERE m.question_id = q.id AND m.control_id = c.id);
